From oo-modules/ghost-engine/core/oo_net_packet.h:

typedef enum {
    OO_PKT_HELLO = 0,
    OO_PKT_PING  = 1,
    OO_PKT_DATA  = 2,
    OO_PKT_FIN   = 3,
} OoPacketKind;

typedef struct {
    OoPacketKind kind;
    uint32_t     peer_id;
    uint32_t     seq;
    uint8_t      payload[32];
    uint8_t      checksum;
} OoPacket;

checksum = XOR of all bytes in payload. The ghost driver calls oo_net_packet_encode() to convert a packet to a LED blink sequence (1=long, 0=short pulse at 100ms base interval).

void conscience_tick(ConscienceEngine *e) {
    PmuSample s;
    pmu_sample(e->pmu, &s);
    if (!s.temp_valid) return;

    ConscPrecision target = consc_select_precision(s.temp_celsius);
    if (target == e->current_precision) return;

    hermes_msg_t msg = {
        .header.kind   = HERMES_CONSCIENCE_DOWNGRADE_REQ,
        .header.source = MODULE_CONSCIENCE,
        .header.dest   = MODULE_BROADCAST,
    };
    hermes_payload_set_u32(&msg, (uint32_t)target);
    hermes_dispatch(e->bus, &msg);
    e->current_precision = target;
}

From oo-modules/evolvion-engine/core/oo_driver_probe.h:

typedef int (*OoDriverProbeFn)(uint32_t device_class, void *hw_ctx);

typedef struct {
    uint32_t         device_class;   /* ACPI/PCI class code */
    const char      *name;
    OoDriverProbeFn  probe;          /* returns 1 if driver claims device */
    void           (*init)(void *hw_ctx);
    void           (*tick)(void *hw_ctx);
} OoDriverDescriptor;

void oo_driver_probe_register(OoDriverDescriptor *desc);
void oo_driver_probe_scan(uint32_t device_class, void *hw_ctx);

evolvion calls oo_driver_probe_register() when the LLM generates a new driver stub, making the driver available to the kernel without reboot.

void dreamion_idle_check(DreamionEngine *e, OoBootCtx *ctx) {
    uint64_t now   = __rdtsc();
    uint64_t delta = now - e->last_input_tsc;

    /* 30s idle threshold at ~3 GHz = 90B cycles */
    if (delta < 90000000000ULL) return;
    if (e->dreaming)            return;

    /* Pull last 8 journal entries as dream seed */
    JTrainEntry seed[8];
    int n = jtrain_read_last(ctx->jtrain_handle, seed, 8);
    if (n <= 0) return;

    dreamion_start(e, seed, n);  /* async: sets e->dreaming = 1 */
}

neuralfs-engine implements a bare-metal vector store. Structure:

typedef struct {
    uint32_t id;
    float    vec[128];   /* 128-dim embedding from LLM hidden state */
    char     tag[64];    /* semantic tag string */
} NfsEntry;

Storage: flat binary file OO_NEURALFS.BIN on the EFI volume.
Search: cosine similarity via djiblas SGEMM (batch dot product of query vec against all entries).
Capacity: 4096 entries max (512 KB for vectors + 256 KB for tags).

neuralfs_search(nfs, query_vec, top_k) returns top_k entries by cosine similarity. Used by symbion for semantic hardware annotation lookup and by memorion for episodic memory retrieval.
